import dspy

class SearchSignature(dspy.Signature):
    '''Search for relevant information.'''
    query: str = dspy.InputField()
    sources: list[str] = dspy.OutputField()

class AnalyzeSignature(dspy.Signature):
    '''Analyze claims from sources.'''
    sources: list[str] = dspy.InputField()
    claims: list[str] = dspy.OutputField()
    reasoning: str = dspy.OutputField()

class research_agent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.search = dspy.ChainOfThought(SearchSignature)
        self.analyze = dspy.ChainOfThought(AnalyzeSignature)

    def forward(self, query):
        sources = self.search(query=query).sources
        analysis = self.analyze(sources=sources)
        return dspy.Prediction(sources=sources, claims=analysis.claims)

import dspy
from typing import List

class WebSearchModule(dspy.Module):
    def __init__(self, search_client):
        super().__init__()
        self.search_client = search_client
        self.generate_search = dspy.ChainOfThought('query -> search_query: str')

    def forward(self, topic: str) -> dspy.Prediction:
        search_query = self.generate_search(topic=topic).search_query
        raw_results = self.search_client.search(search_query, num_results=5)
        sources = [r['snippet'] + '\nURL: ' + r['url'] for r in raw_results]
        return dspy.Prediction(sources=sources, query=search_query)

