import vex

class VerifiedResearchAgent(research_agent):
    def forward(self, query):
        # Verify search results
        search_result = vex.verify(
            lambda: self.search(query=query),
            checks=[vex.check.source_verification(min_sources=3)]
        )

        # Verify analysis chain-of-thought
        analysis_result = vex.verify(
            lambda: self.analyze(sources=search_result.sources),
            checks=[
                vex.check.claim_accuracy(threshold=0.8),
                vex.check.recency(days=90)
            ]
        )

        return dspy.Prediction(
            sources=search_result.sources,
            claims=analysis_result.claims
        )

import vex
from research_agent import research_agent

@vex.workflow([
    vex.step('search', checks=[vex.check.source_verification()]),
    vex.step('analyze', checks=[vex.check.claim_accuracy(), vex.check.recency()]),
    vex.step('synthesize', checks=[vex.check.bias_detection()]),
    fallback='human_review'
])
def production_research_agent(query: str, max_retries=3):
    agent = research_agent()

    for attempt in range(max_retries):
        try:
            result = agent.forward(query)
            verified_result = vex.verify_result(result)
            return verified_result
        except vex.VerificationError as e:
            print(f'Verification failed (attempt {attempt+1}): {e}')
            if attempt == max_retries - 1:
                return {'status': 'human_review_needed', 'query': query, 'error': str(e)}
